// Normalize the CallRail webhook payload. CallRail sends fields at the top
// level OR nested under `body` depending on the webhook version. Handle both.
const input = $input.first().json;
const src = input.body || input;

// CallRail post-call webhooks always include `id` (the call ID).
const callId = src.id || src.call_id || '';
if (!callId) {
  throw new Error('No call id in webhook payload');
}

return [{
  json: {
    callId,
    raw: src
  }
}];

// Take the full CallRail record and shape it for both the AI summarizer and
// the hub.db ingest endpoint.
const c = $input.first().json;

function toE164(p) {
  if (!p) return '';
  const digits = String(p).replace(/\D/g, '');
  if (digits.length === 10) return '+1' + digits;
  if (digits.length === 11 && digits.startsWith('1')) return '+' + digits;
  return digits ? '+' + digits : '';
}

// CallRail returns customer_phone_number already in E.164, but be defensive.
const phone = toE164(c.customer_phone_number);
const trackingPhone = toE164(c.tracking_phone_number);

// CallRail puts geo placeholders like 'DECATUR AL' or 'WIRELESS CALLER' in
// customer_name when no contact match exists. Skip those — we'd rather have
// an empty caller_name than misleading text in push notifications.
const rawName = (c.customer_name || '').trim();
const isGeoPlaceholder =
  /^[A-Z][A-Z\s]+$/.test(rawName) ||
  /TOLLFREE|WIRELESS|UNKNOWN|CALLER/i.test(rawName);
const callerName = isGeoPlaceholder ? '' : rawName;

const transcript = c.transcription || '';
const callRailSummary = c.call_summary || '';

return [{
  json: {
    callId: c.id,
    phone,
    trackingPhone,
    callerName,
    rawCustomerNameField: rawName,
    city: c.customer_city || '',
    state: c.customer_state || '',
    direction: c.direction,
    duration: c.duration || 0,
    answered: !!c.answered,
    voicemail: !!c.voicemail,
    startTime: c.start_time,
    transcript,
    callRailSummary,
    transcriptAvailable: transcript.length > 50
  }
}];

