CALLER: {{ $json.callerName || $json.phone }}
DURATION: {{ Math.round(($json.duration || 0) / 60) }} min
VOICEMAIL: {{ $json.voicemail }}
DIRECTION: {{ $json.direction }}

TRANSCRIPT:
{{ $json.transcript || $json.callRailSummary || '(no transcript available)' }}

