// Merge the AI summary back onto the call data. Claude returns the text in
// `content[0].text` on the n8n Anthropic node.
const call = $('Normalize Call Data').first().json;
const ai = $input.first().json;

let aiOneSentence = '';
if (ai && ai.content && Array.isArray(ai.content) && ai.content[0]) {
  aiOneSentence = (ai.content[0].text || '').trim();
} else if (typeof ai === 'string') {
  aiOneSentence = ai.trim();
}

// Fallback if Claude failed: use CallRail's own summary, capped to 25 words.
if (!aiOneSentence) {
  aiOneSentence = (call.callRailSummary || '').split(/\s+/).slice(0, 25).join(' ');
}

return [{
  json: { ...call, aiOneSentence }
}];

// Build the Pushover notification body. We pull the customer record returned
// by Phoenix Hub (`customer.name`, `customer.total_calls`, etc.) and combine
// it with the AI summary for a rich push.
const call = $('Merge AI Summary').first().json;
const hub = $input.first().json || {};
const cust = hub.customer || {};

const displayName =
  cust.name && cust.name.trim() ? cust.name :
  call.callerName ? call.callerName :
  call.phone;

const durationMin = Math.round((call.duration || 0) / 60);
const durationLabel = call.duration < 60
  ? `${call.duration}s`
  : `${durationMin} min`;

let stateBadge = '';
if (call.voicemail) stateBadge = '📭 Voicemail · ';
else if (!call.answered) stateBadge = '⛔ Missed · ';
else if (call.direction === 'inbound') stateBadge = '📞 Inbound · ';
else stateBadge = '📤 Outbound · ';

const totalCalls = cust.total_calls || 0;
const totalRev = cust.total_revenue || 0;
const customerStat = totalCalls > 1
  ? `\n\n${totalCalls}× caller${totalRev > 0 ? ` · $${Math.round(totalRev).toLocaleString()} lifetime` : ''}`
  : (totalCalls === 1 ? '\n\nFirst-time caller' : '');

const title = `${stateBadge}${displayName} · ${durationLabel}`;
const body  = `${call.aiOneSentence || call.callRailSummary || '(no summary)'}${customerStat}`;

// Pushover priority: voicemail/missed = high (1), inbound answered = normal (0)
const priority = (call.voicemail || !call.answered) ? 1 : 0;

return [{
  json: {
    title,
    message: body,
    priority,
    url: `https://app.callrail.com/calls/${call.callId}`,
    url_title: 'Open in CallRail'
  }
}];

// Final response back to CallRail (it doesn't actually read this, but n8n
// needs a terminal node for the webhook to return 200).
return [{
  json: {
    ok: true,
    callId: $('Merge AI Summary').first().json.callId,
    ingestedAt: new Date().toISOString()
  }
}];
